const body = $input.first().json.body || {};
const aspect_ratio = body.aspect_ratio || '9:16';
const resolutions = { '9:16': {width: 1080, height: 1920}, '16:9': {width: 1920, height: 1080}, '1:1': {width: 1080, height: 1080} };
const res = resolutions[aspect_ratio] || resolutions['9:16'];
return [{ json: { ...body, aspect_ratio, width: res.width, height: res.height } }];

const { execSync } = require('child_process');
const item = items[0].json;
const text = (item.scenes || []).map(s => s.narration || '').filter(Boolean).join('. ').substring(0, 2000);
const v = item.video_id;
const dir = '/workspace/video_assets/' + v;
execSync('mkdir -p ' + dir, { shell: '/bin/bash' });
execSync('edge-tts --voice "' + item.tts_voice + '" --text "' + text + '" --write-media "' + dir + '/voice.mp3"', { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { ...item, voice_path: dir + '/voice.mp3' } }];

const item = items[0].json;
const scenes = item.scenes || [];
return scenes.map(function(s, i) { return { json: { video_id: item.video_id, query: s.search_keywords ? s.search_keywords[0] : item.title, duration: s.seconds || 6, width: item.width, height: item.height, index: i } }; });

var hits = $input.first().json.hits || [];
if (hits.length == 0) return [{ json: { url: null } }];
var url = hits[0].videos ? (hits[0].videos.large ? hits[0].videos.large.url : hits[0].videos.medium ? hits[0].videos.medium.url : null) : null;
return [{ json: { url: url, id: hits[0].id } }];

var execSync = require('child_process').execSync;
var i = items[0].json;
var dir = '/workspace/video_assets/' + i.video_id + '/clips';
var sz = i.width + 'x' + i.height;
execSync('mkdir -p ' + dir, { shell: '/bin/bash' });

if (!i.url) {
  execSync('ffmpeg -y -f lavfi -i color=c=black:s=' + sz + ':r=30 -t ' + i.duration + ' -c:v libx264 -preset fast ' + dir + '/s_' + i.index + '.mp4', { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash' });
  return [{ json: { path: dir + '/s_' + i.index + '.mp4', fallback: true } }];
}

try {
  execSync('ffmpeg -y -i "' + i.url + '" -t ' + i.duration + ' -vf scale=' + sz + ':force_original_aspect_ratio=decrease,pad=' + sz + ':(ow-iw)/2:(oh-ih)/2,setsar=1 -c:v libx264 -preset fast -an ' + dir + '/s_' + i.index + '.mp4', { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
} catch(e) {
  execSync('ffmpeg -y -f lavfi -i color=c=black:s=' + sz + ':r=30 -t ' + i.duration + ' -c:v libx264 -preset fast ' + dir + '/s_' + i.index + '.mp4', { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash' });
}
return [{ json: { path: dir + '/s_' + i.index + '.mp4' } }];

var execSync = require('child_process').execSync;
var i = items[0].json;
var dir = '/workspace/video_assets/' + i.video_id + '/clips';
var files = execSync('ls ' + dir + '/s_*.mp4 2>/dev/null | sort -V', { encoding: 'utf-8', shell: '/bin/bash' }).trim();
if (!files) throw new Error('Ingen scener');
execSync('echo "' + files + '" | sed "s/^/file \'/;s/$/\'/" > ' + dir + '/list.txt && ffmpeg -y -f concat -safe 0 -i ' + dir + '/list.txt -c:v libx264 -preset fast -c:a aac ' + dir + '/concat.mp4', { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { concat: dir + '/concat.mp4' } }];

var execSync = require('child_process').execSync;
var i = items[0].json;
var v = i.video_id;
var u = i.user_id;
var dir = '/workspace/video_assets/' + v;
var supabase = $env.SUPABASE_URL;
var key = $env.SUPABASE_SERVICE_ROLE_KEY;

try { execSync('ffmpeg -y -i ' + dir + '/concat.mp4 -i ' + dir + '/voice.mp3 -c:v copy -c:a aac -shortest ' + dir + '/final.mp4', { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' }); } catch(e) { execSync('cp ' + dir + '/concat.mp4 ' + dir + '/final.mp4'); }

var path = u + '/' + v + '/final.mp4';
try { execSync('curl -sf -X POST ' + supabase + '/storage/v1/object/videos/' + path + ' -H "Authorization: Bearer ' + key + '" -H "Content-Type: video/mp4" --data-binary @' + dir + '/final.mp4', { encoding: 'utf-8', timeout: 600000, shell: '/bin/bash' }); } catch(e) { throw new Error('Upload: ' + e.message); }
return [{ json: { url: supabase + '/storage/v1/object/public/videos/' + path } }];
